import { Anthropic } from '@anthropic-ai/sdk';

const anthropic = new Anthropic({
  betas: ["context-management-2025-06-27"], // Enable context editing
  context_management: {
    edits: [
      {
        type: "clear_tool_uses_20250919",
        trigger: { type: "tool_uses", value: 2 }, // When 2 new tool uses
        keep: { type: "tool_uses", value: 1 }     // Keep 1 most recent
      }
    ]
  }
});

const response = await anthropic.messages.create({
  model: "claude-4-sonnet-20251027", // Sonnet 4.5+
  messages: conversationHistory,
  max_tokens: 1000,
  tools: yourTools
});

// Check applied edits
if (response.provider_data?.context_management?.applied_edits) {
  const edits = response.provider_data.context_management.applied_edits;
  console.log(`✅ Saved: ${edits[-1].cleared_input_tokens} tokens`);
  console.log(`Cleared: ${edits[-1].cleared_tool_uses} tool uses`);
}

context_management: {
  edits: [
    {
      type: "clear_tool_uses_20250919",
      trigger: { type: "tool_uses", value: 2 },
      keep: { type: "tool_uses", value: 1 }
    }
  ]
}

if (response.provider_data?.context_management?.applied_edits) {
  const edits = response.provider_data.context_management.applied_edits;
  const lastEdit = edits[edits.length - 1];

  console.log(`Tokens saved: ${lastEdit.cleared_input_tokens}`);
  console.log(`Tool uses cleared: ${lastEdit.cleared_tool_uses}`);
}

// Memory tool stores insights outside context window
context_management: {
  edits: [
    {
      type: "clear_tool_uses_20250919",
      trigger: { type: "tool_uses", value: 2 },
      keep: { type: "tool_uses", value: 1 }
    }
  ],
  memory: {
    enabled: true,
    directory: "/path/to/memory" // Client-side storage
  }
}

edits: [
  {
    type: "clear_tool_uses_20250919",
    trigger: { type: "tool_uses", value: 3 }, // 3 new tool uses
    keep: { type: "tool_uses", value: 2 }      // Keep 2 most recent
  },
  {
    type: "clear_thinking_blocks",
    trigger: { type: "token_threshold", value: 150000 },
    keep: { type: "thinking_blocks", value: 1 }
  }
]

// Before context editing clears tool results
async function backupToolResults(toolResults) {
  await fs.writeFileSync(
    '/backups/tool-results-' + Date.now() + '.json',
    JSON.stringify(toolResults)
  );
}

// Check for applied edits
if (response.provider_data?.context_management?.applied_edits) {
  const lastEdit = response.provider_data.context_management.applied_edits[-1];
  if (lastEdit.cleared_tool_uses > 0) {
    console.log(`⚠️ ${lastEdit.cleared_tool_uses} tool results cleared`);
    // Optionally restore from backup if needed
  }
}

// Agent reads files, runs tests, grep searches
const tools = [
  { name: "read_file", description: "Read file contents" },
  { name: "run_tests", description: "Execute test suite" },
  { name: "grep", description: "Search codebase" }
];

// Context editing configured
const response = await anthropic.messages.create({
  betas: ["context-management-2025-06-27"],
  context_management: {
    edits: [
      {
        type: "clear_tool_uses_20250919",
        trigger: { type: "tool_uses", value: 2 },
        keep: { type: "tool_uses", value: 1 }
      }
    ]
  },
  model: "claude-4-sonnet-20251027",
  tools: tools
});

// After 50 tool calls:
// Cleared: 48 tool uses (kept 2 most recent)
// Saved: 142,000 tokens
// Agent continues refactoring without interruption

// Agent discovers root cause, saves to memory
context_management: {
  edits: [
    {
      type: "clear_tool_uses_20250919",
      trigger: { type: "tool_uses", value: 2 },
      keep: { type: "tool_uses", value: 1 }
    }
  ],
  memory: {
    enabled: true,
    directory: "/app/memory"
  }
}

// Session 1: Find root cause → save to memory
await saveToMemory({
  key: "auth-module-root-cause",
  value: "JWT token expiry bug on line 847 of auth.ts"
});

// Session 2: Clear context, recall from memory
const rootCause = await readFromMemory("auth-module-root-cause");
// Agent knows previous debugging insights without keeping 8,000 tokens
